-- Read-only generated repair. It never inserts or deletes locations.
begin;
create temporary table location_coordinate_repairs (id uuid primary key, latitude double precision not null, longitude double precision not null, coordinate_source text not null, coordinate_checked_at date not null) on commit drop;
update public.locations l
set latitude = r.latitude, longitude = r.longitude, coordinate_source = r.coordinate_source, coordinate_checked_at = r.coordinate_checked_at
from location_coordinate_repairs r
where l.id = r.id and (l.latitude is null or l.longitude is null);
commit;
